<?phpnamespace PC_CPQ\Helpers;if ( ! defined( 'ABSPATH' ) )	exit;class Utilities{	/**	 * @method decamelize	 * converts camel case to snake case	 * @params string (string)	 */	static public function decamelize( $string )	{		return strtolower( preg_replace( [ '/([a-z\d])([A-Z])/', '/([^_])([A-Z][a-z])/' ], '$1_$2', $string ) );	}	/**	 * @method minify_html	 * minifies html by removing whitespace and comments	 * @params string (string)	 */	static public function minify_html( $string )	{		$search = array(			// Remove whitespaces after tags			'/\>[^\S ]+/s',			// Remove whitespaces before tags			'/[^\S ]+\</s',			// Remove multiple whitespace sequences			'/(\s)+/s',			// Removes comments			'/<!--(.|\s)*?-->/'		);		$replace = array( '>', '<', '\\1' );		return preg_replace( $search, $replace, $string );	}}